module mac_sat (input clk, input rst_n, input valid,
                input signed [3:0] a, input signed [3:0] b, output signed [7:0] acc);
  reg  signed [7:0] r;
  wire signed [8:0] prod = a * b;
  wire signed [9:0] nxt  = r + prod;
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)     r <= 8'sd0;
    else if (valid) begin
      if      (nxt >  127) r <= 8'sd127;
      else if (nxt < -128) r <= -8'sd128;
      else                 r <= nxt[7:0];
    end
  end
  assign acc = r;
endmodule

